IOT_QUESTIONS_PART5 = [{'question': 'An organisation discovers that 200 of its IP cameras have been compromised and are generating 3Gbps of outbound DDoS traffic. What is the correct immediate response sequence?', 'options': [{'text': 'Immediately factory reset all 200 cameras to remove the malware then reconnect them to the network', 'explanation': 'Factory resetting without first blocking outbound traffic allows the DDoS attack to continue during the reset process. Blocking outbound traffic must happen first to stop the attack immediately.', 'correct': False}, {'text': 'Block outbound traffic from the camera VLAN at the perimeter firewall isolate the affected segment preserve forensic evidence then plan remediation', 'explanation': 'Correct. Immediate priority is stopping the attack by blocking outbound traffic from the IoT segment at the firewall. Then isolate the segment to prevent spread, preserve network traffic captures and device logs for forensic analysis, identify the infection vector, factory reset and update firmware on all affected cameras, and implement controls to prevent reinfection before reconnecting.', 'correct': True}, {'text': 'Contact the camera vendor immediately and wait for their guidance before taking any action', 'explanation': 'Waiting for vendor guidance while 200 cameras actively participate in a DDoS attack delays critical containment. Immediate network-level containment must happen first with vendor engagement happening in parallel.', 'correct': False}, {'text': 'Power off all 200 cameras immediately to stop the attack', 'explanation': 'Physical power-off may not be practical for 200 distributed cameras and destroys volatile forensic evidence. Network-level traffic blocking at the firewall stops the attack immediately while preserving forensic capability.', 'correct': False}], 'overall_explanation': 'IoT DDoS response priority: 1) Block outbound attack traffic at network level, 2) Isolate compromised segment from rest of network, 3) Preserve forensic evidence (traffic captures, any available device logs), 4) Identify infection vector to prevent reinfection, 5) Factory reset and firmware update affected devices, 6) Implement controls before reconnecting. Speed of containment is critical to limit DDoS impact on targets.', 'domain': 'IoT Security - Incident Response'}, {'question': 'During IoT incident response a security team wants to perform forensic analysis on a compromised smart home hub. What specific challenges make IoT forensics more difficult than traditional PC forensics?', 'options': [{'text': 'IoT forensics is simpler than PC forensics because IoT devices store less data making analysis faster', 'explanation': 'IoT forensics is more complex not simpler than PC forensics due to proprietary operating systems, limited logging, non-standard storage formats, and the difficulty of acquiring device memory without disrupting evidence.', 'correct': False}, {'text': 'IoT devices have proprietary operating systems limited logging capabilities non-standard storage formats and may not support standard forensic tools requiring specialist techniques', 'explanation': 'Correct. IoT forensic challenges: proprietary embedded operating systems require vendor-specific tools, minimal logging means limited evidence availability, non-standard storage formats require specialised extraction tools, volatile memory evidence is lost on device power cycle, physical chip-off techniques may be required for storage extraction, and firmware analysis requires reverse engineering skills.', 'correct': True}, {'text': 'IoT forensics is impossible because IoT devices encrypt all stored data making extraction impossible', 'explanation': 'While encryption is a factor not all IoT devices encrypt storage. Physical extraction techniques and chip-off analysis can access storage regardless of software-level encryption in many cases.', 'correct': False}, {'text': 'IoT forensics only requires network traffic analysis because IoT devices store all data in the cloud', 'explanation': 'Many IoT devices store significant data locally including configuration, logs, and operational data. Network traffic analysis is one forensic source among many not the only approach.', 'correct': False}], 'overall_explanation': 'IoT forensic techniques: network traffic capture (most reliable source), cloud platform log analysis, firmware extraction for analysis, JTAG/UART access to device memory if available, flash memory chip-off extraction, and physical examination for tampering evidence. Establish forensic procedures before incidents occur as IoT evidence is fragile and easily destroyed.', 'domain': 'IoT Security - Incident Response'}, {'question': 'What is the Shodan search engine and why is it relevant to IoT vulnerability management?', 'options': [{'text': 'Shodan is a social media platform where IoT security researchers share vulnerability discoveries', 'explanation': 'Shodan is not a social media platform. It is an internet-connected device search engine that continuously scans and indexes internet-facing devices including IoT devices.', 'correct': False}, {'text': 'Shodan continuously scans the internet indexing internet-facing devices allowing organisations to discover their own exposed IoT assets and attackers to find vulnerable targets', 'explanation': 'Correct. Shodan scans the entire internet and indexes all responsive devices including IoT devices, their open ports, services, banners, and sometimes even default credentials. Organisations should use Shodan to discover their own internet-exposed IoT assets before attackers do. Attackers use Shodan to find vulnerable targets at scale.', 'correct': True}, {'text': 'Shodan is only accessible to government cybersecurity agencies and is not available to private organisations', 'explanation': 'Shodan is publicly accessible with free and paid tiers. Security professionals, researchers, and unfortunately attackers all have access to Shodan for discovering internet-exposed devices.', 'correct': False}, {'text': 'Shodan only indexes web servers and cannot discover IoT devices or industrial control systems', 'explanation': 'Shodan specifically indexes a vast range of internet-connected devices including IP cameras, routers, industrial control systems, smart home devices, and any device with an internet-accessible service. IoT discovery is one of its primary use cases.', 'correct': False}], 'overall_explanation': 'Shodan for IoT vulnerability management: regularly search for your organisations IP ranges to discover unexpectedly exposed IoT devices, search for specific IoT product models to identify exposed instances, use Shodan monitoring alerts for new exposures, check if any devices show default credentials in banners, and use findings to prioritise remediation. If your IoT devices appear on Shodan treat it as a critical finding requiring immediate action.', 'domain': 'IoT Security - Incident Response'}, {'question': 'An IoT manufacturer discovers a critical remote code execution vulnerability in their devices firmware affecting 2 million deployed devices. What responsible disclosure and patch deployment process should they follow?', 'options': [{'text': 'Immediately publish the vulnerability details publicly to warn users before developing a patch', 'explanation': 'Publishing vulnerability details before a patch is available gives attackers a roadmap to exploit 2 million devices with no defence available. Responsible disclosure coordinates public disclosure timing with patch availability.', 'correct': False}, {'text': 'Develop and test a patch notify relevant CERTs develop a communication plan then simultaneously release the patch and disclose the vulnerability coordinating with major IoT platforms for rapid update deployment', 'explanation': 'Correct. Responsible IoT vulnerability disclosure: develop and thoroughly test the patch, notify relevant CERTs (ICS-CERT, national CERTs), prepare customer communications, coordinate with IoT platform providers (AWS IoT, Azure IoT) for update notification, release patch and disclose vulnerability simultaneously, provide clear remediation guidance, and monitor patch deployment rates escalating urgency if uptake is slow.', 'correct': True}, {'text': 'Quietly patch the vulnerability without any public disclosure to avoid reputational damage', 'explanation': 'Silent patching without disclosure violates responsible disclosure principles, may breach legal requirements in some jurisdictions, and leaves customers unaware of the risk before they receive the patch. Customers may also be entitled to know about vulnerabilities affecting their devices.', 'correct': False}, {'text': 'Wait until 100% of devices have received the patch before disclosing the vulnerability to ensure no devices are at risk', 'explanation': 'Achieving 100% patch deployment before disclosure is impossible in practice. Responsible disclosure involves coordinated timing that balances patch availability with reasonable deployment time not waiting for complete deployment.', 'correct': False}], 'overall_explanation': 'IoT vulnerability disclosure timeline: Day 0 - vulnerability discovered, notify CERT and major cloud platforms in confidence. Days 1-30 - develop and test patch. Day 30 - notify major IoT platform providers for update orchestration. Day 45 - release patch to all devices and publish security advisory. Day 90 - publish full technical details. Monitor patch adoption and escalate urgency for slow-updating devices.', 'domain': 'IoT Security - Incident Response'}, {'question': 'What is the purpose of an IoT security incident response plan and what OT-specific elements must it include that differ from a standard IT incident response plan?', 'options': [{'text': 'An IoT incident response plan is identical to an IT incident response plan with no modifications needed', 'explanation': 'IoT incident response requires specific adaptations for the unique characteristics of IoT environments including limited device logging, diverse proprietary platforms, physical device access requirements, and the potential safety implications of IoT in critical environments.', 'correct': False}, {'text': 'An IoT IR plan must address limited device logging proprietary platform diversity mass device remediation procedures physical device access requirements and safety implications for IoT in critical environments', 'explanation': 'Correct. IoT-specific IR plan elements: procedures for devices with minimal logging (rely on network captures), playbooks for each IoT platform in use, mass remediation procedures for fleet-wide incidents, physical access procedures for remote devices, vendor escalation contacts for proprietary platforms, cloud platform forensic evidence collection procedures, and safety assessment for IoT in medical or industrial contexts.', 'correct': True}, {'text': 'An IoT IR plan only needs to cover network isolation procedures as all other IoT incidents are handled through vendor support', 'explanation': 'IoT incident response encompasses much more than network isolation. Forensic evidence collection, mass remediation, cloud platform investigation, regulatory notification, and customer communication all require specific procedures in an IoT IR plan.', 'correct': False}, {'text': 'IoT incident response plans are only required for organisations with more than 1000 IoT devices', 'explanation': 'IoT incident response planning is important for any organisation deploying IoT devices regardless of scale. The consequences of an unplanned response to an IoT incident can be severe regardless of fleet size.', 'correct': False}], 'overall_explanation': 'IoT IR plan essentials: asset inventory enabling rapid identification of affected devices, network isolation procedures for IoT segments, cloud platform forensic evidence procedures for each platform in use, mass firmware update and factory reset procedures, vendor escalation contacts, regulatory notification requirements for IoT incidents, customer communication templates, and post-incident review process for improving IoT security controls.', 'domain': 'IoT Security - Incident Response'}, {'question': 'A security team is conducting an IoT vulnerability assessment. Why should they avoid using standard IT vulnerability scanners like Nessus directly against IoT devices?', 'options': [{'text': 'Nessus licences do not cover IoT devices making its use legally prohibited in IoT environments', 'explanation': 'Licence restrictions are not the primary concern. The fundamental issue is that active scanning probes can crash or disrupt IoT devices creating operational incidents.', 'correct': False}, {'text': 'Active scanning probes can crash IoT devices cause firmware corruption or trigger unintended device actions due to limited processing capacity and non-standard protocol implementations', 'explanation': 'Correct. IoT devices have limited processing capacity and non-standard embedded operating systems. Active scan probes that IT systems handle without issue can cause IoT devices to crash, reboot, corrupt firmware, or trigger unexpected actions. A crashed IoT camera, medical device, or building automation controller can create significant operational or safety issues.', 'correct': True}, {'text': 'Nessus cannot detect any IoT vulnerabilities making it useless for IoT assessments regardless of the risk of running it', 'explanation': 'While IoT-specific scanners provide better coverage Nessus does detect some IoT vulnerabilities. The primary concern with running it is the risk of device disruption not its detection capability.', 'correct': False}, {'text': 'IoT devices are immune to the vulnerabilities that Nessus scans for making scanning pointless', 'explanation': 'IoT devices are vulnerable to many of the same vulnerability types that Nessus scans for. The concern is the risk of scanning disrupting devices not IoT immunity to vulnerabilities.', 'correct': False}], 'overall_explanation': 'Safe IoT vulnerability assessment approaches: passive network traffic analysis identifying device types and firmware versions, configuration review using vendor management interfaces, firmware binary analysis in isolated environments, OWASP IoT Top 10 manual assessment, review of vendor security advisories against asset inventory, and physical security assessment. Active scanning should only occur on isolated test devices identical to production.', 'domain': 'IoT Security - Incident Response'}, {'question': 'What is the significance of CVE-2021-20090 and similar IoT router vulnerabilities for enterprise IoT security managers?', 'options': [{'text': 'CVE-2021-20090 only affects home routers and has no relevance to enterprise IoT deployments', 'explanation': 'Enterprise IoT deployments often use consumer-grade routers and gateways especially in distributed deployments. Router vulnerabilities affect enterprise IoT infrastructure not just home environments.', 'correct': False}, {'text': 'Path traversal vulnerabilities in IoT routers and gateways can allow unauthenticated access to management interfaces affecting both consumer and enterprise IoT deployments and requiring immediate patching or replacement', 'explanation': 'Correct. CVE-2021-20090 is a path traversal vulnerability affecting multiple IoT router firmware versions allowing unauthenticated access to management interfaces. It demonstrates that IoT infrastructure components like routers and gateways are themselves vulnerable devices that require vulnerability management not just the IoT devices they connect.', 'correct': True}, {'text': 'CVE numbers are only assigned to software vulnerabilities and IoT hardware is not assigned CVEs', 'explanation': 'CVEs are assigned to vulnerabilities in any technology including IoT device firmware, hardware implementations, and embedded software. IoT devices receive CVE assignments regularly.', 'correct': False}, {'text': 'Router vulnerabilities like CVE-2021-20090 are automatically patched by internet service providers making enterprise action unnecessary', 'explanation': 'ISPs do not patch enterprise equipment. Enterprise IoT security managers are responsible for vulnerability management of all IoT infrastructure including routers and gateways on their networks.', 'correct': False}], 'overall_explanation': 'IoT infrastructure vulnerability management covers not just end devices but also IoT gateways, routers, concentrators, and management platforms. These infrastructure components often run embedded firmware with the same vulnerability categories as IoT end devices including path traversal, authentication bypass, and command injection. Include all IoT infrastructure in vulnerability management scope.', 'domain': 'IoT Security - Incident Response'}, {'question': 'An IoT security manager wants to establish metrics to measure the effectiveness of the IoT security programme. Which metrics are most meaningful?', 'options': [{'text': 'The number of IoT devices purchased in the last year is the most meaningful metric for programme effectiveness', 'explanation': 'Procurement volume measures investment not security effectiveness. Meaningful metrics measure security outcomes such as vulnerability exposure, detection capability, and incident response performance.', 'correct': False}, {'text': 'Percentage of IoT assets with known critical vulnerabilities mean time to detect IoT anomalies percentage of devices with current firmware and IoT incident response exercise results', 'explanation': 'Correct. Meaningful IoT security metrics: percentage of fleet with unmitigated critical vulnerabilities (measures risk exposure), mean time to detect IoT anomalies (measures detection capability), percentage of devices running current firmware (measures patch compliance), vendor access sessions with full logging (measures supply chain control), and incident response exercise completion and results (measures resilience).', 'correct': True}, {'text': 'The number of IoT security policies documented is the primary indicator of programme maturity', 'explanation': 'Policy documentation is a process maturity indicator not an effectiveness measure. Outcome metrics measuring actual security posture improvements are more meaningful than process documentation counts.', 'correct': False}, {'text': 'IoT security programme effectiveness cannot be measured and should be evaluated qualitatively only', 'explanation': 'IoT security programme effectiveness can and should be measured quantitatively. Outcome-based metrics provide objective evidence of improvement and support business case development for continued investment.', 'correct': False}], 'overall_explanation': 'IoT security metrics framework: asset visibility (percentage of IoT devices in inventory), vulnerability exposure (critical unmitigated CVEs on production devices), patch compliance (percentage running current firmware), detection capability (mean time to detect anomalies), incident response (time to contain IoT incidents), and supply chain (percentage of vendor sessions fully logged and approved).', 'domain': 'IoT Security - Incident Response'}, {'question': 'What is the security risk of purchasing IoT devices from untrusted or unverified vendors and how should procurement controls address this?', 'options': [{'text': 'Vendor reputation has no bearing on IoT device security as all devices contain the same hardware components', 'explanation': 'Vendor security practices, firmware development processes, vulnerability disclosure policies, and update support commitments vary enormously between vendors and directly impact device security throughout the deployment lifetime.', 'correct': False}, {'text': 'Untrusted vendors may supply devices with backdoors pre-installed malware or permanent vulnerabilities that cannot be patched requiring vendor security assessment before procurement', 'explanation': 'Correct. Supply chain risks from untrusted IoT vendors: pre-installed backdoors providing vendor access to deployed networks, malware in device firmware, weak security defaults that cannot be hardened, no vulnerability disclosure programme, no firmware update support, and counterfeit devices that fail to meet security specifications. Vendor security assessment before procurement prevents these risks.', 'correct': True}, {'text': 'All IoT devices sold legally must meet minimum security standards making vendor assessment unnecessary', 'explanation': 'Minimum IoT security standards vary significantly by jurisdiction and product category. Many markets have no mandatory IoT security requirements. Vendor assessment remains essential regardless of legal minimum standards.', 'correct': False}, {'text': 'The lowest cost IoT vendor should always be selected as cost savings can fund additional security controls', 'explanation': 'Cost savings from selecting insecure IoT vendors are typically far outweighed by the security costs of managing vulnerabilities, responding to incidents, and replacing devices that cannot be adequately secured. Security requirements must be primary procurement criteria.', 'correct': False}], 'overall_explanation': 'IoT vendor security assessment criteria: vulnerability disclosure programme existence and responsiveness, historical CVE record and patch response times, firmware update support commitment (minimum 5 years), security certifications (ISO 27001, SOC 2), penetration testing evidence, software bill of materials (SBOM) availability, and contractual security requirements. Include security requirements in RFPs and procurement contracts.', 'domain': 'IoT Security - Incident Response'}, {'question': 'What is the importance of maintaining a software bill of materials (SBOM) for IoT devices and how does it support vulnerability management?', 'options': [{'text': 'An SBOM is only relevant for enterprise software applications and provides no value for IoT device security management', 'explanation': 'SBOMs are particularly valuable for IoT devices which typically include numerous open source components each potentially containing vulnerabilities. SBOMs enable rapid vulnerability impact assessment across device fleets.', 'correct': False}, {'text': 'An SBOM lists all software components and versions in IoT firmware enabling rapid identification of which devices are affected when vulnerabilities are discovered in component libraries', 'explanation': 'Correct. An IoT device SBOM lists every software component including the OS kernel, libraries, and application code with version numbers. When a vulnerability like Log4Shell is disclosed the SBOM enables immediate identification of which devices include the vulnerable component without requiring full firmware analysis of each device model.', 'correct': True}, {'text': 'SBOMs are proprietary documents that IoT vendors are legally prohibited from sharing with customers', 'explanation': 'SBOMs are increasingly required by regulation and customer contracts. The US Executive Order on Cybersecurity 2021 requires SBOMs for federal government software. Vendors sharing SBOMs with customers is encouraged not prohibited.', 'correct': False}, {'text': 'SBOMs only need to be created once at initial device release and do not need to be updated when firmware is updated', 'explanation': 'SBOMs must be updated with each firmware release as component versions change. An outdated SBOM may miss newly introduced vulnerable components or incorrectly flag components that have been updated.', 'correct': False}], 'overall_explanation': 'IoT SBOM benefits: rapid vulnerability impact assessment when CVEs are disclosed, informed procurement decisions based on component security history, licence compliance management, supply chain transparency, and support for regulatory compliance. US Executive Order 14028 requires SBOMs for federal software. The EU Cyber Resilience Act will require SBOMs for products sold in the EU. Request SBOMs in IoT procurement contracts.', 'domain': 'IoT Security - Incident Response'}]